class Solution {
    public int numberOfWays(int n, int x, int y) {
        long mod = (long) 1e9 + 7;
        long[] dp = new long[x + 1];
        dp[0] = 1;
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= x; j++) {
                dp[j] = (dp[j] + dp[j - 1]) % mod;
            }
        }
        long ans = 0;
        for (int i = 1; i <= x; i++) {
            ans = (ans + (y - i + 1) * dp[i]) % mod;
        }
        return (int) ans;
    }
}
